import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";

export function SobaDetalji() {
  const { idSoba } = useParams();
  const [rezervacije, setRezervacije] = useState([]);
  const [datumOd, setDatumOd] = useState("");
  const [datumDo, setDatumDo] = useState("");
  const [brojOsoba, setBrojOsoba] = useState("");
  const [soba, setSoba] = useState(null);
  const [gosti, setGosti] = useState([]);
  const [idGosta, setIdGosta] = useState("");

  // Učitaj sobu
  useEffect(() => {
    fetch(`http://localhost:8080/rooms/${idSoba}`)
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.value) setSoba(data.data.value);
      })
      .catch((err) => console.error("Greška pri učitavanju sobe:", err));
  }, [idSoba]);

  // Učitaj postojeće rezervacije za sobu
  useEffect(() => {
    fetch(`http://localhost:8080/reservations/getReservationsForRoom/${idSoba}`)
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.values) setRezervacije(data.data.values);
      })
      .catch((err) => console.error("Greška pri učitavanju rezervacija:", err));
  }, [idSoba]);

  // Učitaj sve goste iz baze
  useEffect(() => {
    fetch("http://localhost:8080/guests/all")
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.values) setGosti(data.data.values);
      })
      .catch((err) => console.error("Greška pri učitavanju gostiju:", err));
  }, []);

  // Dodavanje nove rezervacije (po recepcionaru)
  const handleAddReservation = async (e) => {
    e.preventDefault();

    if (!soba || !idGosta) {
      alert("Odaberite gosta i proverite da je soba učitana.");
      return;
    }

    const datumP = new Date(datumOd);
    const datumO = new Date(datumDo);
    const brojNoci = Math.ceil((datumO - datumP) / (1000 * 60 * 60 * 24));

    if (brojNoci <= 0) {
      alert("Datum odjave mora biti posle datuma prijave!");
      return;
    }

    const ukupanIznos = soba.tipSobe?.cenaPoNoci * brojNoci * brojOsoba;

    const novaRez = {
      datumPrijave: datumOd,
      datumOdjave: datumDo,
      brojOsoba: parseInt(brojOsoba),
      gost: { idGost: parseInt(idGosta) },
      soba: { idSoba: parseInt(idSoba) },
    };

    try {
      const response = await fetch(
        "http://localhost:8080/reservations/createByReceptionist",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(novaRez),
        }
      );

      const data = await response.json();

      if (!response.ok) {
        alert("Greška: " + (data.message || "Neuspešno dodavanje!"));
        return;
      }

      alert(data.message || "Rezervacija uspešno dodata!");
      setRezervacije((prev) => [...prev, novaRez]);
    } catch (err) {
      console.error("Greška:", err);
      alert("Greška pri kreiranju rezervacije!");
    }
  };

  return (
    <>
      <NavBarRecepcionar />
      <div style={{ padding: "40px" }}>
        <h2>Rezervacije za sobu #{idSoba}</h2>

        {rezervacije.length > 0 ? (
          <table style={{ width: "100%", borderCollapse: "collapse", marginTop: "20px" }}>
            <thead>
              <tr style={{ backgroundColor: "#e7b7ffff" }}>
                <th>ID</th>
                <th>Gost</th>
                <th>Datum prijave</th>
                <th>Datum odjave</th>
                <th>Broj osoba</th>
                <th>Ukupan iznos (RSD)</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {rezervacije.map((r) => (
                <tr key={r.idRezervacija}>
                  <td>{r.idRezervacija}</td>
                  <td>{r.gost?.email || "Nepoznat"}</td>
                  <td>{r.datumPrijave}</td>
                  <td>{r.datumOdjave}</td>
                  <td>{r.brojOsoba}</td>
                  <td>{r.ukupanIznos?.toFixed(2) || "-"}</td>
                  <td>{r.statusRezervacije}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p>Nema rezervacija za ovu sobu.</p>
        )}

        <hr style={{ margin: "30px 0" }} />

        <h3>Kreiraj novu rezervaciju (recepcionar)</h3>
        <form onSubmit={handleAddReservation}>
          <label>Izaberi gosta:</label>
          <select
            value={idGosta}
            onChange={(e) => setIdGosta(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px", width: "300px" }}
          >
            <option value="">-- Odaberi gosta --</option>
            {gosti.map((g) => (
              <option key={g.idGost} value={g.idGost}>
                {g.ime} {g.prezime} ({g.email})
              </option>
            ))}
          </select>

          <label>Datum prijave:</label>
          <input
            type="date"
            value={datumOd}
            onChange={(e) => setDatumOd(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px" }}
          />

          <label>Datum odjave:</label>
          <input
            type="date"
            value={datumDo}
            onChange={(e) => setDatumDo(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px" }}
          />

          <label>Broj osoba:</label>
          <input
            type="number"
            value={brojOsoba}
            onChange={(e) => setBrojOsoba(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px", width: "100px" }}
          />

          {datumOd && datumDo && brojOsoba && soba && (
            <p style={{ marginTop: "10px", fontWeight: "bold" }}>
              Ukupan iznos:{" "}
              {(soba.tipSobe.cenaPoNoci *
                Math.ceil((new Date(datumDo) - new Date(datumOd)) / (1000 * 60 * 60 * 24)) *
                brojOsoba
              ).toFixed(2)}{" "}
              RSD
            </p>
          )}

          <button
            type="submit"
            style={{
              backgroundColor: "#b84aff",
              color: "white",
              border: "none",
              padding: "8px 15px",
              borderRadius: "6px",
              cursor: "pointer",
            }}
          >
            Dodaj rezervaciju
          </button>
        </form>
      </div>
      <Footer />
    </>
  );
}
